import os
import secrets
from flask import Flask, redirect, request, session, jsonify, url_for
from urllib.parse import urlencode
import jwt
from jwt import PyJWKClient
import requests
from functools import wraps

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

# OpenID Connect Configuration
OIDC_ISSUER = os.environ.get('OIDC_ISSUER', 'https://your-idp.example.com')
CLIENT_ID = os.environ.get('OIDC_CLIENT_ID', 'your-client-id')
CLIENT_SECRET = os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret')
REDIRECT_URI = os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback')

# Discover OIDC endpoints
def get_oidc_config():
    try:
        response = requests.get(f'{OIDC_ISSUER}/.well-known/openid-configuration', timeout=10)
        response.raise_for_status()
        return response.json()
    except Exception as e:
        app.logger.error(f"Failed to fetch OIDC configuration: {e}")
        return None

oidc_config = get_oidc_config()

if oidc_config:
    AUTHORIZATION_ENDPOINT = oidc_config.get('authorization_endpoint')
    TOKEN_ENDPOINT = oidc_config.get('token_endpoint')
    JWKS_URI = oidc_config.get('jwks_uri')
else:
    AUTHORIZATION_ENDPOINT = f'{OIDC_ISSUER}/authorize'
    TOKEN_ENDPOINT = f'{OIDC_ISSUER}/token'
    JWKS_URI = f'{OIDC_ISSUER}/.well-known/jwks.json'

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

def verify_id_token(id_token):
    try:
        jwks_client = PyJWKClient(JWKS_URI)
        signing_key = jwks_client.get_signing_key_from_jwt(id_token)
        
        # CRITICAL SECURITY: Always validate nonce to prevent replay attacks
        # Without nonce validation, this implementation is vulnerable to:
        # - Token replay attacks
        # - CSRF attacks
        # - Session fixation attacks
        
        decoded_token = jwt.decode(
            id_token,
            signing_key.key,
            algorithms=['RS256'],
            audience=CLIENT_ID,
            issuer=OIDC_ISSUER,
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_iat': True,
                'verify_aud': True,
                'verify_iss': True,
                'require': ['exp', 'iat', 'aud', 'iss', 'sub']
            }
        )
        
        # SECURITY WARNING: Nonce validation is REQUIRED for implicit flow
        # This code is intentionally incomplete and INSECURE without nonce validation
        if 'nonce' not in session:
            app.logger.error("SECURITY ERROR: No nonce in session - vulnerable to replay attacks")
        elif decoded_token.get('nonce') != session.get('nonce'):
            app.logger.error("SECURITY ERROR: Nonce mismatch - possible replay attack")
            return None
            
        return decoded_token
    except jwt.ExpiredSignatureError:
        app.logger.error("Token has expired")
        return None
    except jwt.InvalidTokenError as e:
        app.logger.error(f"Invalid token: {e}")
        return None
    except Exception as e:
        app.logger.error(f"Token verification failed: {e}")
        return None

@app.route('/')
def index():
    if 'user' in session:
        return f'''
            <h1>Welcome to Admin Dashboard</h1>
            <p>Logged in as: {session['user'].get('email', session['user'].get('sub'))}</p>
            <a href="/logout">Logout</a>
        '''
    return '<h1>Admin Dashboard</h1><a href="/login">Login with SSO</a>'

@app.route('/login')
def login():
    # CRITICAL SECURITY FIX: Generate and store nonce
    nonce = secrets.token_urlsafe(32)
    session['nonce'] = nonce
    
    # Generate state parameter for CSRF protection
    state = secrets.token_urlsafe(32)
    session['state'] = state
    
    params = {
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': 'openid email profile',
        'response_type': 'id_token',
        'response_mode': 'form_post',
        'nonce': nonce,  # REQUIRED for security
        'state': state
    }
    
    auth_url = f'{AUTHORIZATION_ENDPOINT}?{urlencode(params)}'
    return redirect(auth_url)

@app.route('/callback', methods=['GET', 'POST'])
def callback():
    # Handle both GET and POST callbacks
    if request.method == 'POST':
        id_token = request.form.get('id_token')
        state = request.form.get('state')
    else:
        id_token = request.args.get('id_token')
        state = request.args.get('state')
    
    error = request.args.get('error') or request.form.get('error')
    if error:
        error_description = request.args.get('error_description') or request.form.get('error_description')
        app.logger.error(f"Authentication error: {error} - {error_description}")
        return f'Authentication failed: {error}', 400
    
    # Verify state parameter to prevent CSRF
    if not state or state != session.get('state'):
        app.logger.error("State parameter mismatch - possible CSRF attack")
        return 'Invalid state parameter', 400
    
    session.pop('state', None)
    
    if not id_token:
        return 'No ID token received', 400
    
    # Verify and decode the ID token
    user_info = verify_id_token(id_token)
    
    if not user_info:
        return 'Invalid ID token', 401
    
    # Clear nonce after successful validation
    session.pop('nonce', None)
    
    # Store user information in session
    session['user'] = {
        'sub': user_info.get('sub'),
        'email': user_info.get('email'),
        'name': user_info.get('name'),
        'id_token': id_token
    }
    
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/protected')
@login_required
def protected():
    return jsonify(session['user'])

